const input = $input.first().json.body;

// QC Executive Summary requires contract_id (not session_id)
if (!input.contract_id) {
  throw new Error("Missing required field: contract_id");
}

if (!input.user_id) {
  throw new Error("Missing required field: user_id");
}

const validated = {
  contract_id: input.contract_id,
  user_id: input.user_id,
  format: input.format || "both",
  regenerate: input.regenerate || false,
  document_type: "executive-summary",
  source_type: "quick_contract",
  requested_at: new Date().toISOString(),
  roleContext: input.roleContext || null,
};

return [{ json: validated }];

const request = $("Validate Request").first().json;
const postgresResult = $input.all();

let cachedDocument = null;
let hasCached = false;

if (postgresResult && postgresResult.length > 0) {
  const firstResult = postgresResult[0].json;
  if (firstResult && firstResult.document_id) {
    cachedDocument = firstResult;
    hasCached = true;
  }
}

let action = "generate_new";
if (hasCached && !request.regenerate) {
  action = "return_cached";
}

const output = {
  contract_id: request.contract_id,
  user_id: request.user_id,
  format: request.format,
  regenerate: request.regenerate,
  document_type: request.document_type,
  source_type: request.source_type,
  requested_at: request.requested_at,
  has_cached: hasCached,
  cached_document: cachedDocument,
  action: action,
  roleContext: request.roleContext || null,
};

return [{ json: output }];

const cached = $("Check Existing Document").first().json;
const request = $("Validate Request").first().json;

return [
  {
    json: {
      success: true,
      cached: true,
      document_id: cached.document_id,
      document_type: "executive-summary",
      source_type: "quick_contract",
      status: cached.status,
      downloads: {
        pdf: cached.storage_path_pdf
          ? `/api/documents/download/${cached.document_id}?format=pdf`
          : null,
        docx: cached.storage_path_docx
          ? `/api/documents/download/${cached.document_id}?format=docx`
          : null,
      },
      preview: cached.preview_data,
      generated_at: cached.created_at,
    },
  },
];

const contractData = $("Fetch Contract Details").first().json;
const recipient = $("Fetch Recipient Details").first().json;
const clauseSummary = $("Fetch Clause Summary").first().json;
const keyClauses = $("Fetch Key Clauses")
  .all()
  .map((item) => item.json);
const agreement = $("Fetch Agreement Status").first().json;
const chatStats = $("Fetch Chat Stats").first().json;
const request = $("Validate Request").first().json;

// Role context for dynamic party labels
const roleContext = request.roleContext || null;
const protectedLabel = roleContext?.protectedPartyLabel || 'Customer';
const providingLabel = roleContext?.providingPartyLabel || 'Provider';

// Build key clause summaries for AI
const keyClauseSummaries = keyClauses
  .map((c) => {
    const flags =
      c.clarence_flags && c.clarence_flags.length > 0
        ? ` [FLAGS: ${c.clarence_flags.join(", ")}]`
        : "";
    return `- ${c.clause_name} (${c.category}): Position ${c.clarence_position}/10, Fairness: ${c.clarence_fairness || "N/A"}${flags}\n  Assessment: ${c.clarence_summary || "No summary"}`;
  })
  .join("\n");

// Parse categories
let categoryBreakdown = "Not available";
try {
  const cats =
    typeof clauseSummary.top_categories === "string"
      ? JSON.parse(clauseSummary.top_categories)
      : clauseSummary.top_categories;
  if (cats && cats.length > 0) {
    categoryBreakdown = cats
      .map((c) => `${c.category}: ${c.clause_count} clauses`)
      .join(", ");
  }
} catch (e) {
  categoryBreakdown = "Parse error";
}

// Calculate negotiation progress
const totalClauses = parseInt(clauseSummary.total_clauses) || 0;
const fullyAgreed = parseInt(agreement.fully_agreed_clauses) || 0;
const progressPct =
  totalClauses > 0 ? Math.round((fullyAgreed / totalClauses) * 100) : 0;

// Determine position balance
const avgPos = parseFloat(clauseSummary.avg_position) || 5;
let positionBalance = "Balanced";
if (avgPos < 4) positionBalance = `Strongly ${protectedLabel}-favoring`;
else if (avgPos < 4.5) positionBalance = `${protectedLabel}-leaning`;
else if (avgPos > 6) positionBalance = `Strongly ${providingLabel}-favoring`;
else if (avgPos > 5.5) positionBalance = `${providingLabel}-leaning`;

const aiContext = {
  // Contract
  contract_id: contractData.contract_id,
  contract_name: contractData.file_name || "Untitled Contract",
  contract_type: contractData.contract_type || "other",
  contract_status: contractData.contract_status,
  contract_created: contractData.contract_created,

  // Initiator
  initiator_name:
    `${contractData.initiator_first_name || ""} ${contractData.initiator_last_name || ""}`.trim() ||
    "Unknown",
  initiator_email: contractData.initiator_email || "Not provided",
  initiator_company: contractData.initiator_company || "Unknown Company",
  initiator_industry: contractData.initiator_industry || "Not specified",

  // Provider (recipient)
  provider_name: recipient.recipient_name || `Unknown ${providingLabel}`,
  provider_email: recipient.recipient_email || "Not provided",
  provider_company: recipient.recipient_company || "Unknown Company",
  provider_status: recipient.recipient_status || "invited",
  provider_first_viewed: recipient.first_viewed_at || "Not yet viewed",

  // Clause Analysis
  total_clauses: totalClauses,
  certified_count: parseInt(clauseSummary.certified_count) || 0,
  avg_position: avgPos,
  min_position: parseFloat(clauseSummary.min_position) || 0,
  max_position: parseFloat(clauseSummary.max_position) || 0,
  position_balance: positionBalance,
  balanced_count: parseInt(clauseSummary.balanced_count) || 0,
  customer_favoring_count: parseInt(clauseSummary.customer_favoring_count) || 0,
  provider_favoring_count: parseInt(clauseSummary.provider_favoring_count) || 0,
  category_breakdown: categoryBreakdown,

  // Agreement Status
  fully_agreed_clauses: fullyAgreed,
  initiator_agreed: parseInt(agreement.initiator_agreed) || 0,
  respondent_agreed: parseInt(agreement.respondent_agreed) || 0,
  queries_raised: parseInt(agreement.queries_raised) || 0,
  negotiation_progress: progressPct,

  // Engagement
  total_messages: parseInt(chatStats.total_messages) || 0,
  initiator_messages: parseInt(chatStats.initiator_messages) || 0,
  respondent_messages: parseInt(chatStats.respondent_messages) || 0,

  // Key clauses for detailed analysis
  key_clause_summaries: keyClauseSummaries || "No clause data available",

  // Metadata
  generated_at: new Date().toISOString(),
};

// Build the full Claude API request body with proper escaping
const userPrompt = `Generate the Executive Summary for this Quick Contract mediation:

CONTRACT: ${aiContext.contract_name} (${aiContext.contract_type})
STATUS: ${aiContext.contract_status}
CREATED: ${aiContext.contract_created}

INITIATOR: ${aiContext.initiator_name} (${aiContext.initiator_company}, ${aiContext.initiator_industry})
PROVIDER: ${aiContext.provider_name} (${aiContext.provider_company}) - Status: ${aiContext.provider_status}

CLAUSE ANALYSIS:
- Total clauses: ${aiContext.total_clauses} (${aiContext.certified_count} CLARENCE-certified)
- Average position: ${aiContext.avg_position}/10 (${aiContext.position_balance})
- Position range: ${aiContext.min_position} to ${aiContext.max_position}
- Fairness: ${aiContext.balanced_count} balanced, ${aiContext.customer_favoring_count} ${protectedLabel}-favoring, ${aiContext.provider_favoring_count} ${providingLabel}-favoring
- Categories: ${aiContext.category_breakdown}

AGREEMENT STATUS:
- Fully agreed (both parties): ${aiContext.fully_agreed_clauses} of ${aiContext.total_clauses} clauses (${aiContext.negotiation_progress}%)
- Initiator agreed: ${aiContext.initiator_agreed}
- Respondent agreed: ${aiContext.respondent_agreed}
- Queries raised: ${aiContext.queries_raised}

ENGAGEMENT:
- Total messages: ${aiContext.total_messages} (Initiator: ${aiContext.initiator_messages}, Respondent: ${aiContext.respondent_messages})

KEY CLAUSES:
${aiContext.key_clause_summaries}`;

const apiBody = {
  model: "claude-sonnet-4-20250514",
  max_tokens: 4096,
  system:
    "You are CLARENCE, the Contract Leverage Analysis and Real-time Negotiation Clearinghouse Engine. You are generating an Executive Summary for a Quick Contract mediation.\n\nGenerate a professional executive summary with these sections. Use markdown headers (**SECTION NAME**) for each:\n\n**DEAL OVERVIEW**\nSummarise the contract between the two parties. Include contract type, clause count, and overall assessment of the contract's position balance. Note: Quick Contracts have CLARENCE-certified positions on a 1-10 scale where 1 = maximum ${providingLabel} flexibility and 10 = maximum ${protectedLabel} protection. The average position indicates overall contract lean.\n\n**PARTY PROFILES**\nBrief profile of both parties based on available information. Note engagement level (messages exchanged, clauses agreed).\n\n**CONTRACT POSITION ANALYSIS**\nAnalyse the contract's position distribution. Highlight the average position, any extreme positions, and the overall fairness assessment. Break down by category where relevant. Note flagged clauses that may need attention.\n\n**KEY CLAUSES REQUIRING ATTENTION**\nFocus on the most significant clauses - those with extreme positions (far from 5/balanced), flags, or queries raised. For each, explain the business implication of the current position.\n\n**NEGOTIATION PROGRESS**\nSummarise current agreement status - how many clauses both parties have agreed on, queries outstanding, and overall trajectory. Comment on engagement levels from chat activity.\n\n**RECOMMENDED NEXT STEPS**\nProvide 3-5 specific, actionable recommendations for progressing the negotiation. Be concrete and reference specific clause areas where movement would be most beneficial.\n\nKeep the tone professional, neutral, and data-driven. CLARENCE is the honest broker - never favour either party. Reference specific numbers and percentages throughout.",
  messages: [
    {
      role: "user",
      content: userPrompt,
    },
  ],
};

// Return both the context (for other nodes) and the pre-built API body
aiContext.api_body = JSON.stringify(apiBody);
return [{ json: aiContext }];

const context = $("Prepare AI Context").first().json;
const aiResponse = $("Parse AI Response").first().json;
const contractData = $("Fetch Contract Details").first().json;
const recipient = $("Fetch Recipient Details").first().json;
const clauseSummary = $("Fetch Clause Summary").first().json;
const keyClauses = $("Fetch Key Clauses")
  .all()
  .map((item) => item.json);
const agreement = $("Fetch Agreement Status").first().json;

// Parse AI sections
const content = aiResponse.content_markdown || "";
const extractSection = (sectionName) => {
  const regex = new RegExp(
    `\\*\\*${sectionName}\\*\\*[\\s\\S]*?(?=\\*\\*[A-Z]|$)`,
    "i",
  );
  const match = content.match(regex);
  if (match) {
    return match[0].replace(/\*\*[A-Z\s&]+\*\*/i, "").trim();
  }
  return "";
};

// Date formatting
const now = new Date();
const generatedDate = now.toLocaleDateString("en-GB", {
  day: "numeric",
  month: "long",
  year: "numeric",
});
const generatedTime = now.toLocaleTimeString("en-GB", {
  hour: "2-digit",
  minute: "2-digit",
});

// Position balance for visual indicator
const avgPos = parseFloat(clauseSummary.avg_position) || 5;
const customerPct = Math.round(((10 - avgPos) / 10) * 100);
const providerPct = 100 - customerPct;

const templateData = {
  // Header
  reportTitle: `Executive Summary: ${context.initiator_company} & ${context.provider_company}`,
  contractName: context.contract_name,
  contractType: context.contract_type,
  generatedDate: generatedDate,
  generatedTime: generatedTime,

  // Initiator
  customer: {
    company: context.initiator_company,
    contact: context.initiator_name,
    email: context.initiator_email,
    industry: context.initiator_industry,
  },

  // Provider
  provider: {
    company: context.provider_company,
    contact: context.provider_name,
    email: context.provider_email,
    status: context.provider_status,
  },

  // Position Analysis
  positions: {
    customer_percentage: customerPct,
    provider_percentage: providerPct,
    avg_position: avgPos,
    total_clauses: context.total_clauses,
    certified: context.certified_count,
    balanced: parseInt(clauseSummary.balanced_count) || 0,
    customer_favoring: parseInt(clauseSummary.customer_favoring_count) || 0,
    provider_favoring: parseInt(clauseSummary.provider_favoring_count) || 0,
  },

  // Agreement
  agreement: {
    fully_agreed: parseInt(agreement.fully_agreed_clauses) || 0,
    total_clauses: context.total_clauses,
    progress_pct: context.negotiation_progress,
    queries: context.queries_raised,
  },

  // AI Sections
  mediation: {
    deal_overview: extractSection("DEAL OVERVIEW") || "Assessment in progress.",
    party_profiles: extractSection("PARTY PROFILES") || "",
    position_analysis: extractSection("CONTRACT POSITION ANALYSIS") || "",
    key_clauses: extractSection("KEY CLAUSES REQUIRING ATTENTION") || "",
    negotiation_progress: extractSection("NEGOTIATION PROGRESS") || "",
    next_steps: extractSection("RECOMMENDED NEXT STEPS") || "",
  },

  // Key clauses for table
  key_clauses: keyClauses.slice(0, 5).map((clause) => ({
    name: clause.clause_name || "Unknown",
    category: clause.category || "General",
    position: clause.clarence_position || "-",
    fairness: clause.clarence_fairness || "-",
    flags: (clause.clarence_flags || []).join(", ") || "None",
  })),

  // Footer
  footer: {
    clarence_version: "1.0",
    document_id: context.contract_id,
    confidentiality: "CONFIDENTIAL - For authorised parties only",
  },
};

console.log("TEMPLATE DATA:", JSON.stringify(templateData, null, 2));

return [
  {
    json: {
      ...aiResponse,
      template_data: templateData,
    },
  },
];

const request = $("Validate Request").first().json;
const templateData = $("Prepare API Template").first().json;

const supabaseProject = "wlrlkvqiakaiydfqqdmu";
const bucket = "documents";
const filename = `${request.contract_id}_qc_exec_summary.pdf`;
const storagePath = `executive-summaries/${filename}`;

const publicUrl = `https://${supabaseProject}.supabase.co/storage/v1/object/public/${bucket}/${storagePath}`;

return [
  {
    json: {
      ...templateData,
      pdf_generated: true,
      storage_path_pdf: storagePath,
      pdf_public_url: publicUrl,
      pdf_bucket: bucket,
      pdf_filename: filename,
    },
  },
];

const apiResponse = $input.first().json;
const previousData = $("Prepare API Template").first().json;

if (apiResponse.status === "success" || apiResponse.download_url) {
  return [
    {
      json: {
        ...previousData,
        pdf_generated: true,
        pdf_url: apiResponse.download_url || apiResponse.url,
        pdf_transaction_id: apiResponse.transaction_ref || apiResponse.id,
        storage_path_pdf: apiResponse.download_url || apiResponse.url,
      },
    },
  ];
} else {
  console.log("PDF generation failed:", apiResponse);
  return [
    {
      json: {
        ...previousData,
        pdf_generated: false,
        pdf_error: apiResponse.message || "PDF generation failed",
        storage_path_pdf: null,
      },
    },
  ];
}

const savedDoc = $("Save Document Record").first().json;
const storageData = $("Process Storage Response").first().json;
const request = $("Validate Request").first().json;

const response = {
  success: true,
  cached: false,
  document_id: savedDoc.document_id,
  document_type: "executive-summary",
  source_type: "quick_contract",
  status: "generated",
  downloads: {
    pdf: storageData.pdf_public_url || null,
    docx: null,
  },
  pdf_public_url: storageData.pdf_public_url || null,
  preview: storageData.preview_data,
  generated_at: savedDoc.created_at,
  metadata: {
    contract_id: request.contract_id,
    storage_path: storageData.storage_path_pdf,
    bucket: storageData.pdf_bucket,
  },
};

return [{ json: response }];

const aiResponse = $input.first().json;
const context = $("Prepare AI Context").first().json;
const request = $("Validate Request").first().json;

const generatedContent =
  aiResponse.content?.[0]?.text ||
  aiResponse.message?.content ||
  aiResponse.text ||
  aiResponse.output ||
  "";

// Extract sections for preview
const sections = [];
const sectionMatches = generatedContent.match(/\*\*([A-Z\s&]+)\*\*/g);
if (sectionMatches) {
  sectionMatches.forEach((match) => {
    sections.push(match.replace(/\*\*/g, "").trim());
  });
}

const documentRecord = {
  contract_id: request.contract_id,
  document_type: "executive-summary",
  source_type: "quick_contract",
  document_name: `Executive Summary - ${context.initiator_company} & ${context.provider_company}`,
  content_markdown: generatedContent,
  preview_data: {
    title: `Executive Summary: ${context.initiator_company} & ${context.provider_company}`,
    generated_at: context.generated_at,
    sections: sections,
    summary: {
      initiator: context.initiator_company,
      provider: context.provider_company,
      contract: context.contract_name,
      clauses: context.total_clauses,
      progress: context.negotiation_progress,
      avg_position: context.avg_position,
    },
  },
  generated_by: request.user_id,
  generation_params: {
    model: "claude-sonnet-4-20250514",
    source_type: "quick_contract",
    context_keys: Object.keys(context),
  },
  ai_model_used: "claude-sonnet-4-20250514",
  status: "generated",
};

return [{ json: documentRecord }];
